+  if (_offset == 0) {
+    return;
+  } else if (_offset == OffsetTop) {
+    st->print("+top");
+  } else if (_offset == OffsetBot) {
+    st->print("+bot");
+  } else {
+    st->print("+%d", _offset);
+  }
+}
